import{_ as t,o as n,c as a,a3 as o}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"78. Gender Transition Leave","description":"","frontmatter":{"title":"78. Gender Transition Leave","eba":"Allied Health Professionals 2021-2026","topics":["leave","preliminary"]},"headers":[],"relativePath":"ebas/allied-health/leave/78-gender-transition-leave.md","filePath":"ebas/allied-health/leave/78-gender-transition-leave.md"}'),r={name:"ebas/allied-health/leave/78-gender-transition-leave.md"};function s(i,e,p,d,l,c){return n(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="_78-gender-transition-leave" tabindex="-1">78. Gender Transition Leave <a class="header-anchor" href="#_78-gender-transition-leave" aria-label="Permalink to &quot;78. Gender Transition Leave&quot;">​</a></h1><p>Note: In this clause 78, ‘up to’ refers to the total amount of Gender Transition Leave an Employee is entitled to access whilst they qualify and does not confer a discretion on the Employer to provide fewer than four (4) weeks paid leave and 48 weeks unpaid leave. That is where the Employee qualifies in accordance with this clause 78 for four (4) weeks paid and 48 weeks unpaid Gender Transition Leave, the Employer must provide them with four (4) weeks paid and 48 weeks unpaid Gender Transition Leave.</p><p><strong>78.1</strong> The Employer encourages a culture that is supportive of transgender and gender diverse Employees and recognises the importance of providing a safe environment for Employees undertaking gender transition.</p><p><strong>78.2</strong> Gender Transition refers to the process where a transgender Employee commences living as a member of another gender. This is sometimes referred to ‘affirming’ their gender. This may occur through medical, social or legal changes.</p><p><strong>78.3</strong> Employees may give effect to their transition in a number of ways and are not required to be undergoing specific types of changes, such as surgery, to access leave under this clause 78.</p><p><strong>78.4</strong> Amount of gender transition leave An Employee (other than a Casual Employee) who commences living as a member of another gender is entitled to Gender Transition Leave for the purpose of supporting the Employee’s transition as follows:</p><p><strong>(a)</strong> up to four (4) weeks (20 days) paid leave for essential and necessary gender affirmation procedures; and</p><p><strong>(b)</strong> up to 48 weeks of unpaid leave.</p><p><strong>78.5</strong> The Gender Transition Leave entitlements outlined in subclause 78.4(a) are available to be taken by the Employee within the first 52 weeks after they commence living as a member of another gender.</p><p><strong>78.6</strong> Essential gender affirmation procedures may include:</p><p><strong>(a)</strong> medical and/or psychological appointments;</p><p><strong>(b)</strong> hormonal appointments;</p><p><strong>(c)</strong> surgery and associated appointments;</p><p><strong>(d)</strong> appointments to alter the Employee’s legal status or amend the Employee’s gender on legal documentation; and/or</p><p><strong>(e)</strong> any other similar necessary appointment or procedure to give effect to the Employee’s transition as agreed with the Employer.</p><p><strong>78.7</strong> An Employee who is entitled to unpaid Gender Transition Leave may, in conjunction with all or part of that leave, utilise accrued Annual or Long Service Leave, provided that the combined total of all paid and unpaid leave taken does not exceed 52 continuous weeks.</p><p><strong>78.8</strong> Gender Transition Leave may be taken as consecutive, single or part days as agreed with the Employer.</p><p><strong>78.9</strong> Leave under this clause 78 will not accrue from year to year and cannot be cashed out on termination of employment.</p><p><strong>78.10</strong> Gender Transition Leave – Casual employees Casual Employees are entitled to access unpaid leave of up to 52 continuous weeks duration for gender transition purposes.</p><p><strong>78.11</strong> Notice and evidence requirements</p><p><strong>(a)</strong> An Employee seeking to access Gender Transition Leave must provide the Employer with at least four (4) weeks’ written notice of their intended commencement date and expected period of leave, unless otherwise agreed by the Employer.</p><p><strong>(b)</strong> An Employee seeking to access Gender Transition Leave may be required to provide suitable supporting documentation or evidence of their attendance at essential gender affirmation procedures. This may be in the form of a document issued by a Registered Health Practitioner, a lawyer, or a State, Territory or Federal government organisation, a State, Territory or Commonwealth statutory declaration or other suitable supporting documentation.</p><p><strong>(c)</strong> For the purpose of this clause 78, Registered Health Practitioner has the same meaning as set out in <a href="/eba/ebas/allied-health/preliminary/4-definitions.html">clause 4</a> (Definitions).</p><p>DEVELOPMENT</p>',24)])])}const h=t(r,[["render",s]]);export{g as __pageData,h as default};
